export default function Login() {
  const handleLogin = () => {
    localStorage.setItem("isAuthenticated", "true");
    window.location.href = "/dashboard";
  };

  return (
    <div style={{ textAlign: "center", marginTop: "100px" }}>
      <h1>Login Page</h1>
      <button onClick={handleLogin}>Login</button>
    </div>
  );
}
